import{_ as e,o as t,c as o,a2 as i}from"./chunks/framework.D5wUhsuj.js";const p=JSON.parse('{"title":"Navigation (React Router)","description":"","frontmatter":{},"headers":[],"relativePath":"android/04-navigation.md","filePath":"android/04-navigation.md"}'),n={name:"android/04-navigation.md"};function r(c,a,d,l,u,s){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="navigation-react-router" tabindex="-1">Navigation (React Router) <a class="header-anchor" href="#navigation-react-router" aria-label="Permalink to &quot;Navigation (React Router)&quot;">​</a></h1><p>Navigace v aplikaci je čistě webová (Single Page Application) a řídí ji knihovna <strong>React Router DOM</strong>.</p><h2 id="architektura-navigace" tabindex="-1">Architektura navigace <a class="header-anchor" href="#architektura-navigace" aria-label="Permalink to &quot;Architektura navigace&quot;">​</a></h2><ul><li><code>&lt;BrowserRouter&gt;</code> v souboru <code>App.jsx</code> definuje cesty (Routes) k jednotlivým stránkám (<code>/</code>, <code>/history</code>, <code>/payment</code>).</li><li><code>&lt;BottomNav&gt;</code> komponenta slouží jako hlavní ovládací prvek pro přepínání základních sekcí na spodní hraně displeje.</li><li>Funkce <code>useNavigate()</code> slouží k programatickému přechodu mezi obrazovkami.</li></ul><h2 id="nativni-integrace" tabindex="-1">Nativní integrace <a class="header-anchor" href="#nativni-integrace" aria-label="Permalink to &quot;Nativní integrace&quot;">​</a></h2><p>Součástí navigace je vlastní komponenta <code>&lt;BackButtonHandler&gt;</code>, která komunikuje přes Capacitor API (<code>@capacitor/app</code>). Zajišťuje, že hardwarové tlačítko &quot;Zpět&quot; na Android zařízeních vrací uživatele v historii React Routeru, nebo bezpečně ukončí aplikaci dvojitým stisknutím na hlavní obrazovce.</p>',6)])])}const h=e(n,[["render",r]]);export{p as __pageData,h as default};
